#include "controller.h"

#include <stdbool.h>
#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static bool controller_check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    // Check if turbidity sensor is stale (more than 1000ms since last valid reading)
    if (controller->has_valid_turbidity && (now_ms - controller->last_turbidity_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        return true;
    }
    // Check if level sensor is stale
    if (controller->has_valid_level && (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        return true;
    }
    return false;
}

static bool controller_should_enter_safe_idle(controller_t *controller, uint32_t now_ms)
{
    // Check for sensor timeout first
    if (controller_check_sensor_timeout(controller, now_ms)) {
        return true;
    }
    return false;
}

static void controller_handle_level_low(controller_t *controller)
{
    // LEVEL < 15: stay in COMPLETE with filter off and drain closed
    if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        controller_set_safe_idle(controller);
        controller->state = CONTROLLER_STATE_COMPLETE;
    }
}

static void controller_handle_filtering(controller_t *controller, uint32_t now_ms)
{
    // If LEVEL < 15, enter COMPLETE state
    if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        controller_set_safe_idle(controller);
        controller->state = CONTROLLER_STATE_COMPLETE;
        return;
    }

    // Check for sensor timeout
    if (controller_check_sensor_timeout(controller, now_ms)) {
        controller_set_safe_idle(controller);
        return;
    }

    // Update clear streak based on turbidity
    if (controller->has_valid_turbidity) {
        if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            // Clear reading, increment streak
            controller->clear_streak_count++;
        } else {
            // Turbidity > 35, reset streak to zero
            controller->clear_streak_count = 0;
        }

        // Check if we should enter SETTLING (streak of 3 clear readings while LEVEL >= 40)
        if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED && 
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->filter_on = false;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_SETTLING;
            controller->settling_started_ms = now_ms;
        }
    } else {
        // No valid turbidity, reset streak and stay in FILTERING (or go to safe idle if timeout)
        controller->clear_streak_count = 0;
        if (controller_check_sensor_timeout(controller, now_ms)) {
            controller_set_safe_idle(controller);
        }
    }
}

static void controller_handle_settling(controller_t *controller, uint32_t now_ms)
{
    // Calculate settling duration
    uint32_t settling_duration_ms = now_ms - controller->settling_started_ms;

    // Check for disturbance: TURB > 40 during SETTLING
    if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
        // Reset clear streak and return to FILTERING
        controller->clear_streak_count = 0;
        controller_set_safe_idle(controller);
        controller->filter_on = true;
        controller->drain_open = false;
        controller->state = CONTROLLER_STATE_FILTERING;
        return;
    }

    // Check if we should open drain: settling >= 400ms, latest TURB <= 35, LEVEL >= 40
    if (settling_duration_ms >= CONTROLLER_SETTLING_MS && 
        controller->has_valid_turbidity && 
        controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
        controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
        // Open drain and enter DRAINING
        controller->filter_on = false;
        controller->drain_open = true;
        controller->state = CONTROLLER_STATE_DRAINING;
        return;
    }

    // If not enough settling time or conditions not met, stay in SETTLING
    if (settling_duration_ms < CONTROLLER_SETTLING_MS) {
        controller->filter_on = false;
        controller->drain_open = false;
        controller->state = CONTROLLER_STATE_SETTLING;
        return;
    }

    // Settling time elapsed but conditions not met - this shouldn't normally happen,
    // but if turbidity becomes invalid or level drops, we might need to handle it
    if (!controller->has_valid_turbidity || controller->last_level < CONTROLLER_MIN_PROCESS_LEVEL) {
        // Go back to safe idle if no valid sensors or level too low
        controller_set_safe_idle(controller);
    } else {
        // Conditions should be met at this point, so we would have opened the drain above
        controller->filter_on = false;
        controller->drain_open = true;
        controller->state = CONTROLLER_STATE_DRAINING;
    }
}

static void controller_handle_draining(controller_t *controller, uint32_t now_ms)
{
    // Check for disturbance: TURB > 50 AND LEVEL >= 40 during DRAINING
    if (controller->has_valid_turbidity && 
        controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
        controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
        // Close drain, turn filter on, reset clear streak, return to FILTERING
        controller->filter_on = true;
        controller->drain_open = false;
        controller->clear_streak_count = 0;
        controller_set_safe_idle(controller);
        controller->state = CONTROLLER_STATE_FILTERING;
        return;
    }

    // If LEVEL < 15, enter COMPLETE state
    if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        controller_set_safe_idle(controller);
        controller->state = CONTROLLER_STATE_COMPLETE;
        return;
    }

    // Otherwise stay in DRAINING with drain open
    controller->filter_on = false;
    controller->drain_open = true;
    controller->state = CONTROLLER_STATE_DRAINING;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    // Handle different input types
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        // Valid turbidity reading - update state but don't force safe idle immediately
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        // Process the state machine based on current state
        switch (controller->state) {
        case CONTROLLER_STATE_SAFE_IDLE:
            // In safe idle, we need both sensors valid before proceeding
            if (!controller->has_valid_level) {
                // Still waiting for level sensor
                controller->filter_on = false;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_SAFE_IDLE;
            } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                // Level is low, enter COMPLETE state
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            } else if (input.turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU && 
                       controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                // Start filtering: TURB > 35 and LEVEL >= 40
                controller->filter_on = true;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_FILTERING;
            } else {
                // Clear reading but level is too low, stay in safe idle
                controller_set_safe_idle(controller);
            }
            break;
        case CONTROLLER_STATE_FILTERING:
            controller_handle_filtering(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_SETTLING:
            controller_handle_settling(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_DRAINING:
            controller_handle_draining(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_COMPLETE:
            // In complete state, stay there unless sensor timeout occurs
            if (controller_check_sensor_timeout(controller, input.now_ms)) {
                controller_set_safe_idle(controller);
            } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            } else {
                // Stay in COMPLETE with drain closed and filter off
                controller_set_safe_idle(controller);
            }
            break;
        default:
            controller_set_safe_idle(controller);
            break;
        }
        break;

    case CONTROLLER_INPUT_LEVEL:
        // Valid level reading - update state but don't force safe idle immediately
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        // Process the state machine based on current state
        switch (controller->state) {
        case CONTROLLER_STATE_SAFE_IDLE:
            // In safe idle, we need both sensors valid before proceeding
            if (!controller->has_valid_turbidity) {
                // Still waiting for turbidity sensor
                controller->filter_on = false;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_SAFE_IDLE;
            } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                // Level is low, enter COMPLETE state
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            } else if (controller->has_valid_turbidity && 
                       controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                // Start filtering: TURB > 35 and LEVEL >= 40
                controller->filter_on = true;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_FILTERING;
            } else {
                // Clear reading but level is too low, stay in safe idle
                controller_set_safe_idle(controller);
            }
            break;
        case CONTROLLER_STATE_FILTERING:
            controller_handle_filtering(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_SETTLING:
            controller_handle_settling(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_DRAINING:
            controller_handle_draining(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_COMPLETE:
            // In complete state, stay there unless sensor timeout occurs or level drops further
            if (controller_check_sensor_timeout(controller, input.now_ms)) {
                controller_set_safe_idle(controller);
            } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            } else {
                // Stay in COMPLETE with drain closed and filter off
                controller_set_safe_idle(controller);
            }
            break;
        default:
            controller_set_safe_idle(controller);
            break;
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        // Sensor timeout - go to safe idle
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        break;

    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        // Invalid sensor data - go to safe idle
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        // No input - check for sensor timeout and process state machine
        uint32_t now_ms = input.now_ms;

        if (controller_check_sensor_timeout(controller, now_ms)) {
            controller_set_safe_idle(controller);
        } else {
            // Process state machine based on current state
            switch (controller->state) {
            case CONTROLLER_STATE_SAFE_IDLE:
                // Stay in safe idle until both sensors are valid
                if (!controller->has_valid_turbidity || !controller->has_valid_level) {
                    controller->filter_on = false;
                    controller->drain_open = false;
                    controller->state = CONTROLLER_STATE_SAFE_IDLE;
                } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                    // Level is low, enter COMPLETE state
                    controller_set_safe_idle(controller);
                    controller->state = CONTROLLER_STATE_COMPLETE;
                } else if (controller->has_valid_turbidity && 
                           controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    // Start filtering: TURB > 35 and LEVEL >= 40
                    controller->filter_on = true;
                    controller->drain_open = false;
                    controller->state = CONTROLLER_STATE_FILTERING;
                } else {
                    // Clear reading but level is too low, stay in safe idle
                    controller_set_safe_idle(controller);
                }
                break;
            case CONTROLLER_STATE_FILTERING:
                controller_handle_filtering(controller, now_ms);
                break;
            case CONTROLLER_STATE_SETTLING:
                controller_handle_settling(controller, now_ms);
                break;
            case CONTROLLER_STATE_DRAINING:
                controller_handle_draining(controller, now_ms);
                break;
            case CONTROLLER_STATE_COMPLETE:
                // In complete state, stay there unless sensor timeout occurs or level drops
                if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                    controller_set_safe_idle(controller);
                    controller->state = CONTROLLER_STATE_COMPLETE;
                } else {
                    // Stay in COMPLETE with drain closed and filter off
                    controller_set_safe_idle(controller);
                }
                break;
            default:
                controller_set_safe_idle(controller);
                break;
            }
        }
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);

    // Set timed_out flag if we entered safe idle due to sensor timeout
    if (controller->state == CONTROLLER_STATE_SAFE_IDLE && 
        !previous_filter_on && !previous_drain_open &&
        previous_state != CONTROLLER_STATE_SAFE_IDLE) {
        output.timed_out = true;
    }

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

#include "controller.h"

#include <stdbool.h>
#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static bool controller_check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    // Check if turbidity sensor is stale (more than 1000ms since last valid reading)
    if (controller->has_valid_turbidity && (now_ms - controller->last_turbidity_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        return true;
    }
    // Check if level sensor is stale
    if (controller->has_valid_level && (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        return true;
    }
    return false;
}

static void controller_handle_filtering(controller_t *controller, uint32_t now_ms)
{
    // If LEVEL < 15, enter COMPLETE state with filter off and drain closed
    if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        controller_set_safe_idle(controller);
        controller->state = CONTROLLER_STATE_COMPLETE;
        return;
    }

    // Check for sensor timeout
    if (controller_check_sensor_timeout(controller, now_ms)) {
        controller_set_safe_idle(controller);
        return;
    }

    // Update clear streak based on turbidity
    if (controller->has_valid_turbidity) {
        if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            // Clear reading, increment streak
            controller->clear_streak_count++;
        } else {
            // Turbidity > 35, reset streak to zero
            controller->clear_streak_count = 0;
        }

        // Check if we should enter SETTLING (streak of 3 clear readings while LEVEL >= 40)
        if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED && 
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->filter_on = false;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_SETTLING;
            controller->settling_started_ms = now_ms;
        }
    } else {
        // No valid turbidity, reset streak and check timeout
        controller->clear_streak_count = 0;
        if (controller_check_sensor_timeout(controller, now_ms)) {
            controller_set_safe_idle(controller);
        }
    }
}

static void controller_handle_settling(controller_t *controller, uint32_t now_ms)
{
    // Calculate settling duration
    uint32_t settling_duration_ms = now_ms - controller->settling_started_ms;

    // Check for disturbance: TURB > 40 during SETTLING
    if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
        // Reset clear streak and return to FILTERING
        controller->clear_streak_count = 0;
        controller_set_safe_idle(controller);
        controller->filter_on = true;
        controller->drain_open = false;
        controller->state = CONTROLLER_STATE_FILTERING;
        return;
    }

    // Check if we should open drain: settling >= 400ms, latest TURB <= 35, LEVEL >= 40
    if (settling_duration_ms >= CONTROLLER_SETTLING_MS && 
        controller->has_valid_turbidity && 
        controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
        controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
        // Open drain and enter DRAINING
        controller->filter_on = false;
        controller->drain_open = true;
        controller->state = CONTROLLER_STATE_DRAINING;
        return;
    }

    // If not enough settling time or conditions not met, stay in SETTLING
    if (settling_duration_ms < CONTROLLER_SETTLING_MS) {
        controller->filter_on = false;
        controller->drain_open = false;
        controller->state = CONTROLLER_STATE_SETTLING;
        return;
    }

    // Settling time elapsed but conditions not met - this shouldn't normally happen,
    // but if turbidity becomes invalid or level drops, we might need to handle it
    if (!controller->has_valid_turbidity || controller->last_level < CONTROLLER_MIN_PROCESS_LEVEL) {
        // Go back to safe idle if no valid sensors or level too low
        controller_set_safe_idle(controller);
    } else {
        // Conditions should be met at this point, so we would have opened the drain above
        controller->filter_on = false;
        controller->drain_open = true;
        controller->state = CONTROLLER_STATE_DRAINING;
    }
}

static void controller_handle_draining(controller_t *controller, uint32_t now_ms)
{
    // Check for disturbance: TURB > 50 AND LEVEL >= 40 during DRAINING
    if (controller->has_valid_turbidity && 
        controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
        controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
        // Close drain, turn filter on, reset clear streak, return to FILTERING
        controller->filter_on = true;
        controller->drain_open = false;
        controller->clear_streak_count = 0;
        controller_set_safe_idle(controller);
        controller->state = CONTROLLER_STATE_FILTERING;
        return;
    }

    // If LEVEL < 15, enter COMPLETE state
    if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        controller_set_safe_idle(controller);
        controller->state = CONTROLLER_STATE_COMPLETE;
        return;
    }

    // Otherwise stay in DRAINING with drain open
    controller->filter_on = false;
    controller->drain_open = true;
    controller->state = CONTROLLER_STATE_DRAINING;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    // Handle different input types based on current state
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        // Valid turbidity reading received
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        // Process state machine based on current state
        switch (controller->state) {
        case CONTROLLER_STATE_SAFE_IDLE:
            // In safe idle, we need both sensors valid before proceeding
            if (!controller->has_valid_level) {
                // Still waiting for level sensor - stay in safe idle
                controller->filter_on = false;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_SAFE_IDLE;
            } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                // Level is low, enter COMPLETE state
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            } else if (input.turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU && 
                       controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                // Start filtering: TURB > 35 and LEVEL >= 40
                controller->filter_on = true;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_FILTERING;
            } else {
                // Clear reading (TURB <= 35) but level is too low, stay in safe idle
                controller_set_safe_idle(controller);
            }
            break;
        case CONTROLLER_STATE_FILTERING:
            controller_handle_filtering(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_SETTLING:
            controller_handle_settling(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_DRAINING:
            controller_handle_draining(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_COMPLETE:
            // In complete state, stay there unless sensor timeout occurs or level drops further
            if (controller_check_sensor_timeout(controller, input.now_ms)) {
                controller_set_safe_idle(controller);
            } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            } else {
                // Stay in COMPLETE with drain closed and filter off
                controller_set_safe_idle(controller);
            }
            break;
        default:
            controller_set_safe_idle(controller);
            break;
        }
        break;

    case CONTROLLER_INPUT_LEVEL:
        // Valid level reading received
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        // Process state machine based on current state
        switch (controller->state) {
        case CONTROLLER_STATE_SAFE_IDLE:
            // In safe idle, we need both sensors valid before proceeding
            if (!controller->has_valid_turbidity) {
                // Still waiting for turbidity sensor - stay in safe idle
                controller->filter_on = false;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_SAFE_IDLE;
            } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                // Level is low, enter COMPLETE state
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            } else if (controller->has_valid_turbidity && 
                       controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                // Start filtering: previous TURB > 35 and current LEVEL >= 40
                controller->filter_on = true;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_FILTERING;
            } else {
                // Previous reading was clear (TURB <= 35) but level is too low, stay in safe idle
                controller_set_safe_idle(controller);
            }
            break;
        case CONTROLLER_STATE_FILTERING:
            controller_handle_filtering(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_SETTLING:
            controller_handle_settling(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_DRAINING:
            controller_handle_draining(controller, input.now_ms);
            break;
        case CONTROLLER_STATE_COMPLETE:
            // In complete state, stay there unless sensor timeout occurs or level drops further
            if (controller_check_sensor_timeout(controller, input.now_ms)) {
                controller_set_safe_idle(controller);
            } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                controller_set_safe_idle(controller);
                controller->state = CONTROLLER_STATE_COMPLETE;
            } else {
                // Stay in COMPLETE with drain closed and filter off
                controller_set_safe_idle(controller);
            }
            break;
        default:
            controller_set_safe_idle(controller);
            break;
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        // Sensor timeout - go to safe idle
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        break;

    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        // Invalid sensor data - go to safe idle
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        // No new input - check for sensor timeout and process state machine
        uint32_t now_ms = input.now_ms;

        if (controller_check_sensor_timeout(controller, now_ms)) {
            controller_set_safe_idle(controller);
        } else {
            // Process state machine based on current state
            switch (controller->state) {
            case CONTROLLER_STATE_SAFE_IDLE:
                // Stay in safe idle until both sensors are valid
                if (!controller->has_valid_turbidity || !controller->has_valid_level) {
                    controller->filter_on = false;
                    controller->drain_open = false;
                    controller->state = CONTROLLER_STATE_SAFE_IDLE;
                } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                    // Level is low, enter COMPLETE state
                    controller_set_safe_idle(controller);
                    controller->state = CONTROLLER_STATE_COMPLETE;
                } else if (controller->has_valid_turbidity && 
                           controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    // Start filtering: TURB > 35 and LEVEL >= 40
                    controller->filter_on = true;
                    controller->drain_open = false;
                    controller->state = CONTROLLER_STATE_FILTERING;
                } else {
                    // Clear reading but level is too low, stay in safe idle
                    controller_set_safe_idle(controller);
                }
                break;
            case CONTROLLER_STATE_FILTERING:
                controller_handle_filtering(controller, now_ms);
                break;
            case CONTROLLER_STATE_SETTLING:
                controller_handle_settling(controller, now_ms);
                break;
            case CONTROLLER_STATE_DRAINING:
                controller_handle_draining(controller, now_ms);
                break;
            case CONTROLLER_STATE_COMPLETE:
                // In complete state, stay there unless sensor timeout occurs or level drops
                if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                    controller_set_safe_idle(controller);
                    controller->state = CONTROLLER_STATE_COMPLETE;
                } else {
                    // Stay in COMPLETE with drain closed and filter off
                    controller_set_safe_idle(controller);
                }
                break;
            default:
                controller_set_safe_idle(controller);
                break;
            }
        }
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);

    // Set timed_out flag if we entered safe idle due to sensor timeout from a non-safe-idle state
    if (controller->state == CONTROLLER_STATE_SAFE_IDLE && 
        !previous_filter_on && !previous_drain_open &&
        previous_state != CONTROLLER_STATE_SAFE_IDLE) {
        output.timed_out = true;
    }

    return output;
}

